@js:
var res;
try {
    var d = JSON.parse(result).list[0];
    if (!d || !d.vod_play_url) {
        res = '<div style="color:#ff5252;padding:20px;text-align:center;">暂无播放源或解析失败</div>';
    } else {
        var froms = d.vod_play_from.split('$$$');
        var urls = d.vod_play_url.split('$$$');
        var html = '<!DOCTYPE html><html><head><meta name="viewport" content="width=device-width,initial-scale=1.0,user-scalable=no"><style>body{padding:10px;background:#1a1a1a;color:#eee;margin:0;font-family:sans-serif}.title{font-size:18px;font-weight:bold;margin-bottom:6px}.warning{font-size:12px;color:#ff5252;font-weight:bold;margin-bottom:10px}video{width:100%;aspect-ratio:16/9;background:#000;border-radius:4px;outline:none}.history{font-size:14px;color:#ff9800;margin:10px 0;font-weight:bold}.line{color:#2196F3;font-size:14px;margin:15px 0 10px;font-weight:bold}.grid{display:grid;grid-template-columns:repeat(5,1fr);gap:8px}.btn{background:#333;color:#ccc;border:1px solid #444;border-radius:4px;padding:8px 0;text-align:center;font-size:13px;cursor:pointer;white-space:nowrap;overflow:hidden;text-overflow:ellipsis}.btn.active{background:#2196F3;color:#fff;border-color:#2196F3}</style></head><body><div class="title">' + (d.vod_name || '未知剧集') + '</div><div class="warning">注意：请勿相信视频内广告</div><video id="vp" controls autoplay playsinline webkit-playsinline></video><div id="ht" class="history">读取中...</div>';
        for (var i = 0; i < froms.length; i++) {
            html += '<div class="line">▶ ' + froms[i] + '</div><div class="grid">';
            var eps = (urls[i] || '').split('#');
            for (var j = 0; j < eps.length; j++) {
                var ep = eps[j].split('$');
                if (ep.length >= 2) html += '<div class="btn" data-url="' + ep[1] + '" onclick="play(this)">' + ep[0] + '</div>';
            }
            html += '</div>';
        }
        html += '<script>var did="hv_"+encodeURIComponent(document.querySelector(".title").innerText),vp=document.getElementById("vp"),ht=document.getElementById("ht"),btns=document.querySelectorAll(".btn");function play(b){btns.forEach(function(x){x.classList.remove("active")});b.classList.add("active");vp.src=b.dataset.url;vp.play().catch(function(){});ht.innerText="正在播放："+b.innerText;try{localStorage.setItem(did,Array.from(btns).indexOf(b))}catch(e){}}vp.onended=function(){var a=document.querySelector(".btn.active"),i=Array.from(btns).indexOf(a);if(i>=0&&i<btns.length-1)play(btns[i+1]);else ht.innerText="🎬 全部播放完毕"};var last=localStorage.getItem(did);if(last!==null&&btns[last])play(btns[last]);else if(btns.length>0)play(btns[0]);else ht.innerText="暂无剧集";</script></body></html>';
        res = html;
    }
} catch (e) {
    res = '<div style="color:red;">代码执行异常: ' + e.message + '</div>';
}
res;

ruleNextPage:
@js:
var nextUrl = '';
try {
    var d = JSON.parse(result);
    var p = parseInt(d.page, 10);
    var pc = parseInt(d.pagecount, 10);
    // 只有当前页码小于总页数时，才生成下一页链接
    if (!isNaN(p) && !isNaN(pc) && p < pc) {
        // baseUrl 是阅读引擎自带的当前 URL 变量
        // 用正则精准替换 pg 参数，生成绝对正确的下一页网络请求
        nextUrl = baseUrl.replace(/pg=\d+/, 'pg=' + (p + 1));
    }
} catch(e) {}
nextUrl;

sortUrl:
@js:
var base = source.getKey();
var wd = source.getVariable();
var out = [];

if (wd) {
    out.push('🔍搜索[' + wd + ']::' + base + '?ac=videolist&wd=' + encodeURIComponent(wd) + '&pg={{page}}');
} else {
    out.push('🔍设变量以搜索::' + base + '?ac=videolist&wd={{source.getVariable()}}&pg={{page}}');
}

try {
    // 性能优化：只请求轻量级接口获取纯分类字典
    var jsonStr = java.ajax(base + '?ac=list');
    var rawCats = JSON.parse(jsonStr).class || [];

    // 抹杀白名单，过滤垃圾分类
    var ignoreIds = [1, 2, 3, 4];
    var validCats = rawCats.filter(function(c) {
        return ignoreIds.indexOf(parseInt(c.type_id, 10)) === -1;
    });

    var parentMap = {};
    validCats.forEach(function(c) {
        parentMap[c.type_id] = c.type_name;
    });

    var catList = validCats.map(function(c) {
        var name = c.type_name;
        // 自动拼装父子结构
        if (c.type_pid && c.type_pid !== 0 && parentMap[c.type_pid]) {
            name = parentMap[c.type_pid] + '-' + name;
        }
        // 核心：输出 URL 必须切换为 videolist 才能拉到图片
        return name + '::' + base + '?ac=videolist&t=' + c.type_id + '&pg={{page}}';
    });

    out = out.concat(catList);
} catch(e) {
    out.push('⚠️网络超时或获取分类失败::' + base + '?ac=videolist&pg={{page}}');
}

out.join('\n');
